/* ========================================================================= */
/* KOSIS FACT 검증용 SAS — 경제활동인구조사 청년층 부가조사 */
/* 지표: [청년층] 표 01. 연령별 수학 여부 */
/* [통계표 단위] 천 명 = 가중값 합 / 1,000,000 (가중값 설계 기준) */
/* ========================================================================= */

DATA work.kosis_fact;
  SET mdis.youth_yymm; /* 실제 라이브러리·테이블명으로 교체 */
  WHERE 가중값 > 0;
  IF NOT (15 <= 만연령 <= 29) THEN DELETE;
RUN;

PROC FREQ DATA=work.kosis_fact;
  TABLES 연령별*조사연도*구분;
  WEIGHT 가중값;
RUN;

/* [검증] PROC PRINT 결과의 Count 합계를 천 명 단위로 환산해 MDIS 웹 결과와 대조 */
